<template>
  <v-parallax
    dark
    height="600"    
    src="https://image.freepik.com/free-vector/bright-background-with-dots_1055-3132.jpg"
  >
    <v-layout align-start row>
      <v-flex xs12 sm12 md12>
        <h2 class="heading" style="color:#000000">Scan for Check-in</h2>
        <qrcode-vue :value="qrcodeValue" :size="size" :level="level"></qrcode-vue>
      </v-flex>
    </v-layout>
    <v-layout align-center row>
      <v-flex xs12 sm12 md12>
        <v-btn round color="primary" class="headline" :href="reservation.guideUrl" target="_blank">Guidebook</v-btn>
      </v-flex>
    </v-layout>
    <v-layout align
  </v-parallax>
</template>

<script>
import store from '@/store'
import { mapState, mapGetters, mapActions } from 'vuex'
import QrcodeVue from 'qrcode.vue'

export default {
  data: () => ({
      size: 250,
      level: 'H',
  }),
  mounted () {
    console.log('this.allIdVerified', this.allIdVerified)
  },
  async beforeRouteEnter (to, from, next) {
    const error = await store.dispatch('checkIn/loadMembers').catch(error => {
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  async beforeRouteUpdate (to, from, next) {
    const error = await store.dispatch('checkIn/loadMembers').catch(error => {      
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  computed: {
    qrcodeValue: {
      get() {
        if (this.username) {
          if (this.password) {
            return JSON.stringify({username: this.username, password: this.password})
          }
        } else {
          return null
        }
      }
    },
    username: {
      get() {
        if (this.reservation) {
          return this.reservation.username
        } else {
          return null
        }
      }
    },
    password: {
      get() {
        if (this.reservation) {
          return this.reservation.checkInDate.replace(/(\d{4})\-(\d{2})\-(\d{2})/, '$1$2$3')
        } else {
          return null
        }
      }
    },
    ...mapState({
      reservation: state => state.checkIn.reservation,
    }),
    ...mapGetters('checkIn', {
      allIdVerified: 'allIdVerified',
    })
  },
  methods: {
  },
  components: {
    QrcodeVue
  }
}
</script>